mapper.update:
UPDATE t_supplier
SET status = #{status}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT FROM t_order o LEFT JOIN t_user u ON o.user_id = u.id LEFT JOIN t_fault_type ft ON o.fault_type_id = ft.id LEFT JOIN t_supplier s ON o.supplier_id = s.id LEFT JOIN t_order_staff os ON o.order_no = os.order_no LEFT JOIN t_staff st ON os.staff_id = st.id WHERE (
(o.supplier_id = #{supplierId}) OR
(o.supplier_id IS NULL AND #{status} = 'pending') )
AND o.order_no = #{orderNo}
AND o.status = #{status}
AND o.create_time >= #{startDate}
AND o.create_time <= #{endDate}
ORDER BY o.create_time DESC
